+  /**
+   * Unregister a hook by ID
+   */
+  unregister(hookId: string): boolean {
+    const entry = this.hooks.get(hookId);
+    if (!entry) {
+      return false;
+    }
+
+    // Remove from event index
+    const eventHooks = this.hooksByEvent.get(entry.event);
+    if (eventHooks) {
+      eventHooks.delete(hookId);
+    }
