+      totalFailures: this.stats.totalFailures,
+      avgExecutionTime,
+    };
+  }
+
+  /**
+   * Record execution statistics
+   */
+  recordExecution(success: boolean, duration: number): void {
+    this.stats.totalExecutions++;
+    if (!success) {
