+  /** Whether execution was aborted */
+  aborted?: boolean;
+
+  /** Number of hooks executed */
+  hooksExecuted: number;
+
+  /** Number of hooks that failed */
+  hooksFailed: number;
+
+  /** Total execution time in milliseconds */
+  executionTime: number;
