+  name: string;
+
+  /** Current status */
+  status: DaemonStatus;
+
+  /** Process ID if running */
+  pid?: number;
+
+  /** Started timestamp */
+  startedAt?: Date;
+
+  /** Last update timestamp */
+  lastUpdateAt?: Date;
+
+  /** Error message if status is 'error' */
+  error?: string;
+
+  /** Execution count */
+  executionCount: number;
+
+  /** Failure count */
+  failureCount: number;
