+
+// ============================================================================
+// Statusline Types
+// ============================================================================
+
+/**
+ * Statusline data
+ */
+export interface StatuslineData {
+  /** V3 implementation progress */
+  v3Progress: {
+    domainsCompleted: number;
+    totalDomains: number;
+    dddProgress: number;
+    modulesCount: number;
+    filesCount: number;
+    linesCount: number;
+  };
