+/**
+ * Worker status
+ */
+export type WorkerStatus = 'pending' | 'running' | 'completed' | 'failed' | 'cancelled';
+/**
+ * Worker configuration
+ */
+export interface WorkerConfig {
+    /** Maximum concurrent workers */
+    maxConcurrent: number;
+    /** Default timeout in milliseconds */
+    defaultTimeout: number;
+    /** Memory limit per worker in MB */
+    memoryLimit: number;
+    /** Enable auto-dispatch based on context */
+    autoDispatch: boolean;
+    /** Priority queue for workers */
+    priorityQueue: boolean;
+}
+/**
+ * Worker instance
+ */
+export interface WorkerInstance {
+    id: string;
+    trigger: WorkerTrigger;
+    context: string;
+    sessionId: string;
+    status: WorkerStatus;
+    progress: number;
+    phase: string;
+    startedAt: Date;
+    completedAt?: Date;
+    result?: WorkerResult;
+    error?: Error;
+    metadata?: Record<string, unknown>;
+}
+/**
+ * Worker result
+ */
+export interface WorkerResult {
+    success: boolean;
+    data?: unknown;
+    artifacts?: WorkerArtifact[];
+    metrics?: WorkerMetrics;
+    summary?: string;
+}
+/**
+ * Worker artifact
+ */
+export interface WorkerArtifact {
+    type: 'file' | 'data' | 'report' | 'suggestion';
+    name: string;
+    content: string | Buffer | Record<string, unknown>;
+    size?: number;
+}
+/**
+ * Worker metrics
+ */
+export interface WorkerMetrics {
+    duration: number;
+    tokensUsed?: number;
+    filesProcessed?: number;
+    itemsAnalyzed?: number;
+    memoryUsed?: number;
+}
+/**
+ * Trigger detection result
+ */
+export interface TriggerDetectionResult {
+    detected: boolean;
+    triggers: WorkerTrigger[];
+    confidence: number;
+    context?: string;
+}
+/**
+ * Worker dispatch options
+ */
+export interface DispatchOptions {
+    priority?: 'low' | 'normal' | 'high' | 'critical';
+    timeout?: number;
+    context?: Record<string, unknown>;
+    callback?: (worker: WorkerInstance) => void;
+}
